const body = $('📥 Webhook Trigger').item.json.body;
const renders = body.renders || [];

return renders
  .filter(r => r.videoUrl)
  .map(r => ({
    json: {
      idioma: r.idioma,
      videoUrl: r.videoUrl,
      titulo: r.titulo,
      descripcion: r.descripcion,
      tags: Array.isArray(r.tags) ? r.tags.join(',') : (r.tags || ''),
      angel_number: body.angel_number,
      grupo: body.grupo,
      grupo_nombre: body.grupo_nombre,
      timestamp: body.timestamp
    }
  }));

const upload = $input.item.json;
const render = $('📦 Preparar Renders').item.json;
const isError = !!(upload.error || upload.status === 'failed');
return [{ json: {
  idioma: render.idioma,
  angel_number: render.angel_number,
  titulo: render.titulo,
  grupo_nombre: render.grupo_nombre,
  status: isError ? 'ERROR' : 'SUCCESS',
  videoId: isError ? null : (upload.id || null),
  errorDetails: isError ? (upload.error?.message || JSON.stringify(upload).slice(0, 200)) : null,
  timestamp: new Date().toISOString()
}}];

